// 'arg' is the layer array — the upstream Python GeoDataFrame routed
// through the Data Pool is auto-wrapped to [{ name, type, geojson }] by
// the AUTK_MAP lifecycle. autk-map's loadCollection rejects
// 'POLYGONS_2D' (valid: 'polygons' / 'roads' / 'points' / 'buildings' /
// 'surface' / 'water' / 'parks' / 'raster' — see autk-map api.d.ts), so
// pass null to let the map infer the type from the feature geometries.
//
// Picking is enabled so selecting a neighborhood propagates 'interacted'
// through the Data Pool to the linked Vega-Lite bar chart.
const map = new AutkMap(container);
await map.init();
for (const layer of arg) {
    map.loadCollection(layer.name, { collection: layer.geojson, type: null });
    map.updateRenderInfo(layer.name, { renderInfo: { isPick: true, isColorMap: true } });
    map.updateThematic(layer.name, {
        collection: layer.geojson,
        property: 'properties.accessibility',
    });
}
map.draw();
return map;
